from django.shortcuts import render, redirect
from django.contrib.auth import authenticate, login
from django.views.decorators.csrf import csrf_exempt
from django.http import HttpResponse
from django.conf import settings
import base64
import xml.etree.ElementTree as ET
import logging

logger = logging.getLogger(__name__)

@csrf_exempt
def saml_acs(request):
    if request.method != 'POST':
        return HttpResponse(status=405)

    # Decode and parse the SAML response
    saml_response = request.POST.get('SAMLResponse')
    if not saml_response:
        return HttpResponse("No SAML Response found", status=400)

    try:
        saml_xml = base64.b64decode(saml_response)
        root = ET.fromstring(saml_xml)
    except Exception as e:
        logger.exception("Failed to parse SAML XML: %s", e)
        return HttpResponse("Invalid SAML Response format", status=400)

    # Basic XML structure validation
    assertion = root.find(".//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion")
    if assertion is None:
        return HttpResponse("Invalid SAML XML structure", status=400)

    # Extract NameID and attributes
    name_id_elem = assertion.find(".//{urn:oasis:names:tc:SAML:2.0:assertion}NameID")
    if name_id_elem is None:
        return HttpResponse("NameID not found in SAML Response", status=400)
    
    name_id = name_id_elem.text
    user_info = {'name_id': name_id}
    
    attributes = assertion.findall(".//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute")
    for attr in attributes:
        attr_name = attr.get('Name')
        attr_value = attr.find(".//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue")
        if attr_name and attr_value is not None:
            user_info[attr_name] = attr_value.text

    # Authenticate user based on NameID
    user = authenticate(request, name_id=user_info['name_id'], attributes=user_info)
    if user is not None:
        login(request, user)
        return redirect(settings.LOGIN_REDIRECT_URL)
    else:
        return HttpResponse("User authentication failed", status=401)

